mapper.sql:
/* wms-inbound-iborderddln-sql-oracle.xml - selectIbOrderHdsql - 입고마감 정보 SQL */ SELECT CHK , CTKEY , CTNM , OWKEY , IBHDTYPECD , IBHDKEY , IBEXPCTDATE , EXTORDERKEY , REQORDERNO , ACKEY , OB_CTNM , ACNM , CLOSEYN , B2BOBCNFRMYN , IBSTATUSCD , INITQTY_SKU , INITQTY , INITQTY_INN , INITQTY_CTN , INITQTY_PLT , INITQTY_SLPRC , EXPCTQTY_SKU , EXPCTQTY , EXPCTQTY_INN , EXPCTQTY_CTN , EXPCTQTY_PLT , EXPCTQTY_SLPRC , IBQTY_SKU , IBQTY , IBQTY_INN , IBQTY_CTN , IBQTY_PLT , IBQTY_SLPRC , CNFRMQTY_SKU , CNFRMQTY , CNFRMQTY_INN , CNFRMQTY_CTN , CNFRMQTY_PLT , CNFRMQTY_SLPRC , DIFQTYYN , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY FROM ( SELECT '0' AS CHK , A.CTKEY , C.CTNM , A.OWKEY , A.IBHDTYPECD , A.IBHDKEY , A.IBEXPCTDATE , A.EXTORDERKEY , A.REQORDERNO , A.ACKEY , CASE WHEN IBHDTYPECD = '30' THEN A.ACNM ELSE '' END AS OB_CTNM , CASE WHEN IBHDTYPECD != '30' THEN A.ACNM ELSE '' END AS ACNM , CASE WHEN SUM(IBDTSTATUSCD) > 0 THEN 'N' ELSE 'Y' END AS CLOSEYN , A.B2BOBCNFRMYN , A.IBSTATUSCD , COALESCE(SUM(INITQTY_SKU), 0) AS INITQTY_SKU , COALESCE(SUM(INITQTY), 0) AS INITQTY , COALESCE(ROUND(SUM(INITQTY_INN), 2), 0) AS INITQTY_INN , COALESCE(ROUND(SUM(INITQTY_CTN), 2), 0) AS INITQTY_CTN , COALESCE(ROUND(SUM(INITQTY_PLT), 2), 0) AS INITQTY_PLT , COALESCE(SUM(INITQTY_SLPRC), 0) AS INITQTY_SLPRC , COALESCE(SUM(EXPCTQTY_SKU), 0) AS EXPCTQTY_SKU , COALESCE(SUM(EXPCTQTY), 0) AS EXPCTQTY , COALESCE(ROUND(SUM(EXPCTQTY_INN), 2), 0) AS EXPCTQTY_INN , COALESCE(ROUND(SUM(EXPCTQTY_CTN), 2), 0) AS EXPCTQTY_CTN , COALESCE(ROUND(SUM(EXPCTQTY_PLT), 2), 0) AS EXPCTQTY_PLT , COALESCE(SUM(EXPCTQTY_SLPRC), 0) AS EXPCTQTY_SLPRC , COALESCE(SUM(IBQTY_SKU), 0) AS IBQTY_SKU , COALESCE(SUM(IBQTY), 0) AS IBQTY , COALESCE(ROUND(SUM(IBQTY_INN), 2), 0) AS IBQTY_INN , COALESCE(ROUND(SUM(IBQTY_CTN), 2), 0) AS IBQTY_CTN , COALESCE(ROUND(SUM(IBQTY_PLT), 2), 0) AS IBQTY_PLT , COALESCE(SUM(IBQTY_SLPRC), 0) AS IBQTY_SLPRC , COALESCE(SUM(CNFRMQTY_SKU), 0) AS CNFRMQTY_SKU , COALESCE(SUM(CNFRMQTY), 0) AS CNFRMQTY , COALESCE(ROUND(SUM(CNFRMQTY_INN), 2), 0) AS CNFRMQTY_INN , COALESCE(ROUND(SUM(CNFRMQTY_CTN), 2), 0) AS CNFRMQTY_CTN , COALESCE(ROUND(SUM(CNFRMQTY_PLT), 2), 0) AS CNFRMQTY_PLT , COALESCE(SUM(CNFRMQTY_SLPRC), 0) AS CNFRMQTY_SLPRC , CASE WHEN COALESCE(SUM(EXPCTQTY), 0) = COALESCE(SUM(CNFRMQTY), 0) THEN 'Y' ELSE 'N' END AS DIFQTYYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IB_HD A INNER JOIN ( SELECT A.CTKEY , A.OWKEY , A.IBHDKEY , A.UPRIBDTKEY , CASE WHEN A.INITQTY > 0 THEN 1 ELSE 0 END AS INITQTY_SKU , A.INITQTY , A.INITQTY / NULLIF(COALESCE(C.ICUNITQTY, 0), 0) AS INITQTY_INN , A.INITQTY / NULLIF(COALESCE(D.ICUNITQTY, 0), 0) AS INITQTY_CTN , A.INITQTY / (NULLIF(COALESCE(D.ICUNITQTY, 0), 0) * NULLIF(COALESCE(D.CPPQTY, 0), 0)) AS INITQTY_PLT , A.INITQTY * B.SLPRC AS INITQTY_SLPRC , CASE WHEN A.EXPCTQTY > 0 THEN 1 ELSE 0 END AS EXPCTQTY_SKU , A.EXPCTQTY , A.EXPCTQTY / NULLIF(COALESCE(C.ICUNITQTY, 0), 0) AS EXPCTQTY_INN , A.EXPCTQTY / NULLIF(COALESCE(D.ICUNITQTY, 0), 0) AS EXPCTQTY_CTN , A.EXPCTQTY / (NULLIF(COALESCE(D.ICUNITQTY, 0), 0) * NULLIF(COALESCE(D.CPPQTY, 0), 0)) AS EXPCTQTY_PLT , A.EXPCTQTY * B.SLPRC AS EXPCTQTY_SLPRC , CASE WHEN A.IBQTY > 0 THEN 1 ELSE 0 END AS IBQTY_SKU , A.IBQTY , A.IBQTY / NULLIF(COALESCE(C.ICUNITQTY, 0), 0) AS IBQTY_INN , A.IBQTY / NULLIF(COALESCE(D.ICUNITQTY, 0), 0) AS IBQTY_CTN , A.IBQTY / (NULLIF(COALESCE(D.ICUNITQTY, 0), 0) * NULLIF(COALESCE(D.CPPQTY, 0), 0)) AS IBQTY_PLT , A.IBQTY * B.SLPRC AS IBQTY_SLPRC , CASE WHEN A.CNFRMQTY > 0 THEN 1 ELSE 0 END AS CNFRMQTY_SKU , A.CNFRMQTY , A.CNFRMQTY / NULLIF(COALESCE(C.ICUNITQTY, 0), 0) AS CNFRMQTY_INN , A.CNFRMQTY / NULLIF(COALESCE(D.ICUNITQTY, 0), 0) AS CNFRMQTY_CTN , A.CNFRMQTY / (NULLIF(COALESCE(D.ICUNITQTY, 0), 0) * NULLIF(COALESCE(D.CPPQTY, 0), 0)) AS CNFRMQTY_PLT , A.CNFRMQTY * B.SLPRC AS CNFRMQTY_SLPRC , CASE WHEN A.IBDTSTATUSCD = '91' OR A.IBDTSTATUSCD = '92' THEN 0 ELSE 1 END AS IBDTSTATUSCD FROM TWORK_INFO_IB_DT A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND B.ICUNITKEY = C.ICUNITKEY AND C.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND B.ICUNITKEY = D.ICUNITKEY AND D.ICUNITTYPECD = 'CTN' ) B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_CT C ON A.CTKEY = C.CTKEY WHERE A.IBSTATUSCD != '99' AND B.UPRIBDTKEY IS NULL AND A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND A.IBHDTYPECD != '50' /* 반품입고 */ GROUP BY A.CTKEY, C.CTNM, A.OWKEY, A.IBHDTYPECD, A.IBHDKEY, A.IBEXPCTDATE, A.REQORDERNO, A.EXTORDERKEY, A.ACKEY, A.ACNM, A.B2BOBCNFRMYN, A.IBSTATUSCD, A.INSERTDATE, A.INSERTURKEY, A.UPDATEDATE, A.UPDATEURKEY ) WHERE 1=1
AND IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND IBSTATUSCD = #{ibstatuscd}
AND IBHDKEY = #{ibhdkey}
AND INSERTURKEY = #{inserturkey}
AND DIFQTYYN = #{difqtyyn}
AND CLOSEYN = #{closeyn}
AND B2BOBCNFRMYN = #{b2bobcnfrmyn}

