mapper.sql:
/* wms-inbound-iborderddln-sql-oracle.xml - selectIbOrderDtsql - 입고 마감 상세 조회 SQL */ SELECT * FROM ( SELECT '0' AS CHK , A.CTKEY , A.OWKEY , A.IBHDKEY , A.IBDTKEY , B.IBHDTYPECD , B.IBEXPCTDATE , CASE WHEN B.IBHDTYPECD = '30' THEN B.ACNM ELSE '' END AS OB_CTNM , CASE WHEN B.IBHDTYPECD != '30' THEN B.ACNM ELSE '' END AS ACNM , A.EXTORDERKEY , B.REQORDERNO , C.ACKEY AS IC_ACKEY , D.ACNM AS IC_ACNM , CASE WHEN E.ASRTDTICKEY IS NOT NULL AND A.UPRIBDTKEY IS NOT NULL THEN E.ASRTMASICKEY ELSE A.ICKEY END AS ASRTMASICKEY , CASE WHEN E.ASRTDTICKEY IS NOT NULL AND A.UPRIBDTKEY IS NOT NULL THEN G.ICNM ELSE C.ICNM END AS ASRTMASICNM , CASE WHEN E.ASRTDTICKEY IS NOT NULL AND A.UPRIBDTKEY IS NOT NULL THEN A.ICKEY END AS ASRTDTICKEY , CASE WHEN E.ASRTDTICKEY IS NOT NULL AND A.UPRIBDTKEY IS NOT NULL THEN C.ICNM END AS ASRTDTICNM , A.ASRTWKTGTYN AS ASRTYN , CTG3.CTGNM AS LV1_CTGNM , CTG2.CTGNM AS LV2_CTGNM , CTG1.CTGNM AS LV3_CTGNM , A.UOM , A.IBDTSTATUSCD , COALESCE(A.INITQTY, 0) AS INITQTY , ROUND(A.INITQTY / NULLIF(COALESCE(I.ICUNITQTY, 0), 0), 2) AS INITQTY_INN , ROUND(A.INITQTY / NULLIF(COALESCE(J.ICUNITQTY, 0), 0), 2) AS INITQTY_CTN , ROUND(A.INITQTY / (NULLIF(COALESCE(J.ICUNITQTY, 0), 0) * NULLIF(COALESCE(J.CPPQTY, 0), 0)), 2) AS INITQTY_PLT , COALESCE(A.INITQTY * C.SLPRC, 0) AS INITQTY_SLPRC
, COALESCE(A.EXPCTQTY, 0) AS EXPCTQTY , ROUND(A.EXPCTQTY / NULLIF(COALESCE(I.ICUNITQTY, 0), 0), 2) AS EXPCTQTY_INN , ROUND(A.EXPCTQTY / NULLIF(COALESCE(J.ICUNITQTY, 0), 0), 2) AS EXPCTQTY_CTN , ROUND(A.EXPCTQTY / (NULLIF(COALESCE(J.ICUNITQTY, 0), 0) * NULLIF(COALESCE(J.CPPQTY, 0), 0)), 2) AS EXPCTQTY_PLT , COALESCE(A.EXPCTQTY * C.SLPRC, 0) AS EXPCTQTY_SLPRC
, COALESCE(A.IBQTY, 0) AS IBQTY , ROUND(A.IBQTY / NULLIF(COALESCE(I.ICUNITQTY, 0), 0), 2) AS IBQTY_INN , ROUND(A.IBQTY / NULLIF(COALESCE(J.ICUNITQTY, 0), 0), 2) AS IBQTY_CTN , ROUND(A.IBQTY / (NULLIF(COALESCE(J.ICUNITQTY, 0), 0) * NULLIF(COALESCE(J.CPPQTY, 0), 0)), 2) AS IBQTY_PLT , COALESCE(A.IBQTY * C.SLPRC, 0) AS IBQTY_SLPRC
, COALESCE(A.CNFRMQTY, 0) AS CNFRMQTY , ROUND(A.CNFRMQTY / NULLIF(COALESCE(I.ICUNITQTY, 0), 0), 2) AS CNFRMQTY_INN , ROUND(A.CNFRMQTY / NULLIF(COALESCE(J.ICUNITQTY, 0), 0), 2) AS CNFRMQTY_CTN , ROUND(A.CNFRMQTY / (NULLIF(COALESCE(J.ICUNITQTY, 0), 0) * NULLIF(COALESCE(J.CPPQTY, 0), 0)), 2) AS CNFRMQTY_PLT , COALESCE(A.CNFRMQTY * C.SLPRC, 0) AS CNFRMQTY_SLPRC
, COALESCE(A.EXPCTQTY, 0) - COALESCE(A.CNFRMQTY, 0) AS NONCNFRMQTY , ROUND((COALESCE(A.EXPCTQTY, 0) - COALESCE(A.CNFRMQTY, 0)) / NULLIF(COALESCE(I.ICUNITQTY, 0), 0), 2) AS NONCNFRMQTY_INN , ROUND((COALESCE(A.EXPCTQTY, 0) - COALESCE(A.CNFRMQTY, 0)) / NULLIF(COALESCE(J.ICUNITQTY, 0), 0), 2) AS NONCNFRMQTY_CTN , ROUND((COALESCE(A.EXPCTQTY, 0) - COALESCE(A.CNFRMQTY, 0)) / (NULLIF(COALESCE(J.ICUNITQTY, 0), 0) * NULLIF(COALESCE(J.CPPQTY, 0), 0)), 2) AS NONCNFRMQTY_PLT , COALESCE((COALESCE(A.EXPCTQTY, 0) - COALESCE(A.CNFRMQTY, 0)) * C.SLPRC, 0) AS NONCNFRMQTY_SLPRC
, CASE WHEN A.IBDTSTATUSCD = '91' OR A.IBDTSTATUSCD = '92' THEN 'Y' ELSE 'N' END AS CLOSEYN , CASE WHEN A.CLAIMSNDYN = 'Y' THEN COALESCE(A.EXPCTQTY, 0) - COALESCE(A.CNFRMQTY, 0) ELSE 0 END AS CLAIMREQQTY , A.CLAIMRSNCONT , A.ICKEY , C.ICNM , COALESCE(A.PLCMSTATUSCD, '00') AS PLCMSTATUSCD , A.UPRIBDTKEY , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IB_DT A INNER JOIN TWORK_INFO_IB_HD B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY LEFT OUTER JOIN TWORK_MST_AC D ON A.CTKEY = D.CTKEY AND C.ACKEY = D.ACKEY LEFT OUTER JOIN TWORK_MST_ASRT E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND A.ICKEY = E.ASRTDTICKEY LEFT OUTER JOIN TWORK_MST_IC G ON A.CTKEY = G.CTKEY AND A.OWKEY = G.OWKEY AND E.ASRTMASICKEY = G.ICKEY INNER JOIN TWORK_MST_CTG CTG1 ON A.CTKEY = CTG1.CTKEY AND A.OWKEY = CTG1.OWKEY AND C.CTGKEY = CTG1.CTGKEY AND CTG1.CTGLV = '3' INNER JOIN TWORK_MST_CTG CTG2 ON CTG1.CTKEY = CTG2.CTKEY AND CTG1.OWKEY = CTG2.OWKEY AND CTG1.UPRCTGKEY = CTG2.CTGKEY AND CTG2.CTGLV = '2' INNER JOIN TWORK_MST_CTG CTG3 ON CTG2.CTKEY = CTG3.CTKEY AND CTG2.OWKEY = CTG3.OWKEY AND CTG2.UPRCTGKEY = CTG3.CTGKEY AND CTG3.CTGLV = '1' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE I ON A.CTKEY = I.CTKEY AND A.OWKEY = I.OWKEY AND C.ICUNITKEY = I.ICUNITKEY AND I.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE J ON A.CTKEY = J.CTKEY AND A.OWKEY = J.OWKEY AND C.ICUNITKEY = J.ICUNITKEY AND J.ICUNITTYPECD = 'CTN' INNER JOIN TWORK_MST_ICBARCODE H ON A.CTKEY = H.CTKEY AND A.OWKEY = H.OWKEY AND A.ICKEY = H.ICKEY AND H.UOM = 'EA' WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND A.IBHDKEY = #{ibhdkey} AND A.IBDTSTATUSCD <> '99'
#{ickey}
AND C.ICNM LIKE '%'|| #{icnm} || '%'
AND H.BARCODE = #{barcode}
) A WHERE 1=1

mapper.select:
/* wms-inbound-iborderddln-sql-oracle.xml - selectIbDtInfoList - 입고 상세 조회 */
SELECT *
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
/*  AND UPRIBDTKEY IS NULL  아소트 자상품 제외 */

/* wms-inbound-iborderddln-sql-oracle.xml - selectIbcfCntrInfoList - 입고 확정 용기 조회 */
SELECT *
  FROM TWORK_INFO_IBCF_CNTR
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
   AND QTY > 0

mapper.update:
/* wms-inbound-iborderddln-sql-oracle.xml - updateIbDtIbqty - 입고 수량 수정 */
UPDATE TWORK_INFO_IB_DT
   SET IBQTY	= CNFRMQTY

	, ASRTWKCOMPLYN = #{asrtwkcomplyn}

	 , UPDATEDATE 	= #{sysdate}
	 , UPDATEURKEY 	= #{surkey}
 WHERE CTKEY 	 = #{ctkey}
   AND OWKEY 	 = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

/* wms-inbound-iborderddln-sql-oracle.xml - updateIbHdDdln - 입고 헤더 마감 */
UPDATE TWORK_INFO_IB_HD
   SET IBSTATUSCD = '91'   /* 마감 */
	 , IBDDLNDATE = #{sysdate}
	 , IBDDLNURKEY = #{surkey}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}

/* wms-inbound-iborderddln-sql-oracle.xml - updateIbDtDdln - 입고 상세 마감 */
UPDATE TWORK_INFO_IB_DT
   SET IBDTSTATUSCD = '91'   /* 마감 */
	 , IBDDLNDATE = #{sysdate}
	 , IBDDLNURKEY = #{surkey}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}

	AND IBDTKEY = #{ibdtkey}

mapper.select:
/* wms-inbound-iborderddln-sql-oracle.xml - selectIbDtDdlnCount - 입고 상세 마감 count */
SELECT COUNT(*)
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTSTATUSCD != '91'

mapper.update:
/* wms-inbound-iborderddln-sql-oracle.xml - updateIbHdClaimReg - 입고 헤더 클레임 등록 */
UPDATE TWORK_INFO_IB_HD
   SET IBSTATUSCD = '92'   /* 클레임 등록 */
	 , CLAIMSNDYN = 'Y'
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}

/* wms-inbound-iborderddln-sql-oracle.xml - updateIbDtClaimReg - 입고 상세 클레임 등록 */
UPDATE TWORK_INFO_IB_DT
   SET IBDTSTATUSCD = '92'   /* 클레임 등록 */
	 , CLAIMSNDYN = 'Y'
	 , CLAIMRSNCONT = #{claimrsncont}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
